+        let record = UFuncLogRecord {
+            fixture_id: "UP-005-policy-unknown-mode".to_string(),
+            seed: 5201,
+            mode: UFuncRuntimeMode::Strict,
+            env_fingerprint: "fnp-ufunc-tests".to_string(),
